import{_ as e,o as r,c as o,a2 as t}from"./chunks/framework.DG4H4-xE.js";const u=JSON.parse('{"title":"附录E：术语表","description":"","frontmatter":{},"headers":[],"relativePath":"appendix-e-glossary.md","filePath":"appendix-e-glossary.md","lastUpdated":1775035907000}'),i={name:"appendix-e-glossary.md"};function l(h,a,n,d,c,s){return r(),o("div",null,[...a[0]||(a[0]=[t('<h1 id="附录e-术语表" tabindex="-1">附录E：术语表 <a class="header-anchor" href="#附录e-术语表" aria-label="Permalink to &quot;附录E：术语表&quot;">​</a></h1><p>本附录定义 Claude Code 文档中使用的关键术语。</p><h2 id="a" tabindex="-1">A <a class="header-anchor" href="#a" aria-label="Permalink to &quot;A&quot;">​</a></h2><h3 id="agent" tabindex="-1">Agent <a class="header-anchor" href="#agent" aria-label="Permalink to &quot;Agent&quot;">​</a></h3><p>智能代理，能够自主执行任务的 AI 实体。在 Claude Code 中，Agent 可以理解用户意图、规划步骤、调用工具并完成复杂任务。</p><h3 id="api-key" tabindex="-1">API Key <a class="header-anchor" href="#api-key" aria-label="Permalink to &quot;API Key&quot;">​</a></h3><p>应用程序接口密钥，用于认证和授权 API 调用。Claude Code 使用 Anthropic API Key 或 OAuth 进行认证。</p><h3 id="auto-mode" tabindex="-1">Auto Mode <a class="header-anchor" href="#auto-mode" aria-label="Permalink to &quot;Auto Mode&quot;">​</a></h3><p>自动模式，一种权限模式，允许 AI 自动执行低风险操作，减少用户确认次数。</p><h2 id="b" tabindex="-1">B <a class="header-anchor" href="#b" aria-label="Permalink to &quot;B&quot;">​</a></h2><h3 id="bypass-mode" tabindex="-1">Bypass Mode <a class="header-anchor" href="#bypass-mode" aria-label="Permalink to &quot;Bypass Mode&quot;">​</a></h3><p>绕过模式，一种权限模式，跳过所有权限检查。极度危险，仅适用于受控环境。</p><h2 id="c" tabindex="-1">C <a class="header-anchor" href="#c" aria-label="Permalink to &quot;C&quot;">​</a></h2><h3 id="cli-command-line-interface" tabindex="-1">CLI (Command Line Interface) <a class="header-anchor" href="#cli-command-line-interface" aria-label="Permalink to &quot;CLI (Command Line Interface)&quot;">​</a></h3><p>命令行界面，用户通过文本命令与程序交互的界面。Claude Code 主要以 CLI 形式运行。</p><h3 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h3><p>上下文，AI 在当前对话中可用的信息集合，包括对话历史、文件内容、系统提示等。</p><h3 id="context-window" tabindex="-1">Context Window <a class="header-anchor" href="#context-window" aria-label="Permalink to &quot;Context Window&quot;">​</a></h3><p>上下文窗口，AI 模型一次可以处理的最大 token 数量。Claude 的上下文窗口为 200K tokens。</p><h3 id="compact" tabindex="-1">Compact <a class="header-anchor" href="#compact" aria-label="Permalink to &quot;Compact&quot;">​</a></h3><p>压缩，将对话历史浓缩为更简洁的摘要，以减少 token 使用。</p><h2 id="d" tabindex="-1">D <a class="header-anchor" href="#d" aria-label="Permalink to &quot;D&quot;">​</a></h2><h3 id="dependency-injection" tabindex="-1">Dependency Injection <a class="header-anchor" href="#dependency-injection" aria-label="Permalink to &quot;Dependency Injection&quot;">​</a></h3><p>依赖注入，一种软件设计模式，将依赖项从外部传入，而不是在内部创建。Claude Code 使用依赖注入来管理工具和服务的实例。</p><h2 id="e" tabindex="-1">E <a class="header-anchor" href="#e" aria-label="Permalink to &quot;E&quot;">​</a></h2><h3 id="entrypoint" tabindex="-1">Entrypoint <a class="header-anchor" href="#entrypoint" aria-label="Permalink to &quot;Entrypoint&quot;">​</a></h3><p>入口点，程序开始执行的位置。在 Claude Code 中，<code>main.tsx</code> 是主入口点。</p><h2 id="f" tabindex="-1">F <a class="header-anchor" href="#f" aria-label="Permalink to &quot;F&quot;">​</a></h2><h3 id="feature-flag" tabindex="-1">Feature Flag <a class="header-anchor" href="#feature-flag" aria-label="Permalink to &quot;Feature Flag&quot;">​</a></h3><p>特性标志，用于控制功能开关的机制。Bun 的 <code>bun:bundle</code> 支持编译时特性标志，实现死代码消除。</p><h3 id="feedback-memory" tabindex="-1">Feedback Memory <a class="header-anchor" href="#feedback-memory" aria-label="Permalink to &quot;Feedback Memory&quot;">​</a></h3><p>反馈记忆，存储用户关于 AI 行为的指导和建议的 Memory 类型。</p><h3 id="fork" tabindex="-1">Fork <a class="header-anchor" href="#fork" aria-label="Permalink to &quot;Fork&quot;">​</a></h3><p>分支，在 Agent 上下文中，指从父 Agent 创建一个继承上下文的子 Agent。</p><h2 id="g" tabindex="-1">G <a class="header-anchor" href="#g" aria-label="Permalink to &quot;G&quot;">​</a></h2><h3 id="git-worktree" tabindex="-1">Git Worktree <a class="header-anchor" href="#git-worktree" aria-label="Permalink to &quot;Git Worktree&quot;">​</a></h3><p>Git 工作树，允许多个工作目录共享同一个 Git 仓库，用于隔离不同分支的开发工作。</p><h3 id="glob" tabindex="-1">Glob <a class="header-anchor" href="#glob" aria-label="Permalink to &quot;Glob&quot;">​</a></h3><p>全局模式，一种文件路径匹配模式，使用通配符（如 <code>*</code> 和 <code>**</code>）匹配多个文件。</p><h2 id="h" tabindex="-1">H <a class="header-anchor" href="#h" aria-label="Permalink to &quot;H&quot;">​</a></h2><h3 id="hook" tabindex="-1">Hook <a class="header-anchor" href="#hook" aria-label="Permalink to &quot;Hook&quot;">​</a></h3><p>钩子，在特定事件发生时执行的代码。Claude Code 使用 hooks 来处理权限检查、工具调用等。</p><h2 id="i" tabindex="-1">I <a class="header-anchor" href="#i" aria-label="Permalink to &quot;I&quot;">​</a></h2><h3 id="in-memory-error" tabindex="-1">In-memory Error <a class="header-anchor" href="#in-memory-error" aria-label="Permalink to &quot;In-memory Error&quot;">​</a></h3><p>内存错误，程序运行时发生的内存相关问题。</p><h3 id="input-schema" tabindex="-1">Input Schema <a class="header-anchor" href="#input-schema" aria-label="Permalink to &quot;Input Schema&quot;">​</a></h3><p>输入模式，定义工具或命令接受的参数结构，通常使用 Zod 库定义。</p><h2 id="l" tabindex="-1">L <a class="header-anchor" href="#l" aria-label="Permalink to &quot;L&quot;">​</a></h2><h3 id="lsp-language-server-protocol" tabindex="-1">LSP (Language Server Protocol) <a class="header-anchor" href="#lsp-language-server-protocol" aria-label="Permalink to &quot;LSP (Language Server Protocol)&quot;">​</a></h3><p>语言服务器协议，一种用于编辑器和语言服务器之间通信的标准协议。Claude Code 通过 LSP 获取代码智能功能。</p><h2 id="m" tabindex="-1">M <a class="header-anchor" href="#m" aria-label="Permalink to &quot;M&quot;">​</a></h2><h3 id="mcp-model-context-protocol" tabindex="-1">MCP (Model Context Protocol) <a class="header-anchor" href="#mcp-model-context-protocol" aria-label="Permalink to &quot;MCP (Model Context Protocol)&quot;">​</a></h3><p>模型上下文协议，Anthropic 推出的开放标准，用于连接 AI 应用与外部工具和数据源。</p><h3 id="memory" tabindex="-1">Memory <a class="header-anchor" href="#memory" aria-label="Permalink to &quot;Memory&quot;">​</a></h3><p>记忆系统，Claude Code 的持久化知识存储系统，允许 AI 跨会话保留信息。</p><h3 id="memory-scope" tabindex="-1">Memory Scope <a class="header-anchor" href="#memory-scope" aria-label="Permalink to &quot;Memory Scope&quot;">​</a></h3><p>记忆作用域，定义 Memory 的可见范围，包括 User、Project、Local 三种级别。</p><h3 id="memoize" tabindex="-1">Memoize <a class="header-anchor" href="#memoize" aria-label="Permalink to &quot;Memoize&quot;">​</a></h3><p>记忆化，一种缓存技术，存储函数计算结果，避免重复计算。</p><h2 id="n" tabindex="-1">N <a class="header-anchor" href="#n" aria-label="Permalink to &quot;N&quot;">​</a></h2><h3 id="node-js" tabindex="-1">Node.js <a class="header-anchor" href="#node-js" aria-label="Permalink to &quot;Node.js&quot;">​</a></h3><p>基于 Chrome V8 引擎的 JavaScript 运行时。Claude Code 可以运行在 Node.js 上，但推荐使用 Bun。</p><h2 id="p" tabindex="-1">P <a class="header-anchor" href="#p" aria-label="Permalink to &quot;P&quot;">​</a></h2><h3 id="permission-mode" tabindex="-1">Permission Mode <a class="header-anchor" href="#permission-mode" aria-label="Permalink to &quot;Permission Mode&quot;">​</a></h3><p>权限模式，定义 AI 可自主执行的操作范围。包括 default、plan、auto、bypass 四种模式。</p><h3 id="plugin" tabindex="-1">Plugin <a class="header-anchor" href="#plugin" aria-label="Permalink to &quot;Plugin&quot;">​</a></h3><p>插件，扩展 Claude Code 功能的第三方代码包。</p><h3 id="project-memory" tabindex="-1">Project Memory <a class="header-anchor" href="#project-memory" aria-label="Permalink to &quot;Project Memory&quot;">​</a></h3><p>项目记忆，存储项目特定信息的 Memory 类型，包括当前状态、决策、已知问题等。</p><h3 id="prompt" tabindex="-1">Prompt <a class="header-anchor" href="#prompt" aria-label="Permalink to &quot;Prompt&quot;">​</a></h3><p>提示词，用户或系统提供给 AI 的指令或问题。</p><h3 id="prompt-cache" tabindex="-1">Prompt Cache <a class="header-anchor" href="#prompt-cache" aria-label="Permalink to &quot;Prompt Cache&quot;">​</a></h3><p>提示词缓存，Claude API 的特性，可以缓存部分提示词，减少重复计算，降低延迟和成本。</p><h2 id="r" tabindex="-1">R <a class="header-anchor" href="#r" aria-label="Permalink to &quot;R&quot;">​</a></h2><h3 id="reference-memory" tabindex="-1">Reference Memory <a class="header-anchor" href="#reference-memory" aria-label="Permalink to &quot;Reference Memory&quot;">​</a></h3><p>引用记忆，存储外部资源链接的 Memory 类型，如文档 URL、监控仪表板等。</p><h3 id="ripgrep-rg" tabindex="-1">Ripgrep (rg) <a class="header-anchor" href="#ripgrep-rg" aria-label="Permalink to &quot;Ripgrep (rg)&quot;">​</a></h3><p>一种极速的文本搜索工具，Grep 工具基于 ripgrep 实现。</p><h2 id="s" tabindex="-1">S <a class="header-anchor" href="#s" aria-label="Permalink to &quot;S&quot;">​</a></h2><h3 id="schema" tabindex="-1">Schema <a class="header-anchor" href="#schema" aria-label="Permalink to &quot;Schema&quot;">​</a></h3><p>模式，定义数据结构的规范。在 Claude Code 中，使用 Zod 库定义工具的输入参数模式。</p><h3 id="scope" tabindex="-1">Scope <a class="header-anchor" href="#scope" aria-label="Permalink to &quot;Scope&quot;">​</a></h3><p>作用域，定义变量的可见范围。在 Memory 系统中，Scope 决定 Memory 的共享级别。</p><h3 id="subagent" tabindex="-1">Subagent <a class="header-anchor" href="#subagent" aria-label="Permalink to &quot;Subagent&quot;">​</a></h3><p>子 Agent，由主 Agent 创建的辅助 Agent，用于处理特定的子任务。</p><h3 id="system-context" tabindex="-1">System Context <a class="header-anchor" href="#system-context" aria-label="Permalink to &quot;System Context&quot;">​</a></h3><p>系统上下文，会话级别的上下文信息，包括 Git 状态、项目信息等，可以被 Prompt Cache 缓存。</p><h3 id="system-prompt" tabindex="-1">System Prompt <a class="header-anchor" href="#system-prompt" aria-label="Permalink to &quot;System Prompt&quot;">​</a></h3><p>系统提示词，定义 AI 的角色、能力和行为规范的提示词。</p><h2 id="t" tabindex="-1">T <a class="header-anchor" href="#t" aria-label="Permalink to &quot;T&quot;">​</a></h2><h3 id="token" tabindex="-1">Token <a class="header-anchor" href="#token" aria-label="Permalink to &quot;Token&quot;">​</a></h3><p>标记，AI 模型处理文本的基本单位。一个 token 约等于 4 个英文字符或 0.75 个单词。</p><h3 id="tool" tabindex="-1">Tool <a class="header-anchor" href="#tool" aria-label="Permalink to &quot;Tool&quot;">​</a></h3><p>工具，AI 可以调用的函数，用于执行特定操作如读写文件、运行命令等。</p><h3 id="typescript" tabindex="-1">TypeScript <a class="header-anchor" href="#typescript" aria-label="Permalink to &quot;TypeScript&quot;">​</a></h3><p>JavaScript 的超集，添加了静态类型支持。Claude Code 使用 TypeScript strict mode 编写。</p><h2 id="u" tabindex="-1">U <a class="header-anchor" href="#u" aria-label="Permalink to &quot;U&quot;">​</a></h2><h3 id="user-context" tabindex="-1">User Context <a class="header-anchor" href="#user-context" aria-label="Permalink to &quot;User Context&quot;">​</a></h3><p>用户上下文，每轮对话可变的上下文信息，如当前工作目录、最近打开的文件等。</p><h3 id="user-memory" tabindex="-1">User Memory <a class="header-anchor" href="#user-memory" aria-label="Permalink to &quot;User Memory&quot;">​</a></h3><p>用户记忆，存储用户个人偏好的 Memory 类型，包括角色背景、沟通风格等。</p><h2 id="v" tabindex="-1">V <a class="header-anchor" href="#v" aria-label="Permalink to &quot;V&quot;">​</a></h2><h3 id="vitepress" tabindex="-1">VitePress <a class="header-anchor" href="#vitepress" aria-label="Permalink to &quot;VitePress&quot;">​</a></h3><p>基于 Vue.js 的静态站点生成器，Claude Code 的文档网站使用 VitePress 构建。</p><h2 id="w" tabindex="-1">W <a class="header-anchor" href="#w" aria-label="Permalink to &quot;W&quot;">​</a></h2><h3 id="workflow-engine" tabindex="-1">Workflow Engine <a class="header-anchor" href="#workflow-engine" aria-label="Permalink to &quot;Workflow Engine&quot;">​</a></h3><p>工作流引擎，管理多步骤任务的执行流程。Book Crafter 使用工作流引擎管理书籍创建流程。</p><h3 id="worktree" tabindex="-1">Worktree <a class="header-anchor" href="#worktree" aria-label="Permalink to &quot;Worktree&quot;">​</a></h3><p>工作树，参见 Git Worktree。</p><h2 id="z" tabindex="-1">Z <a class="header-anchor" href="#z" aria-label="Permalink to &quot;Z&quot;">​</a></h2><h3 id="zod" tabindex="-1">Zod <a class="header-anchor" href="#zod" aria-label="Permalink to &quot;Zod&quot;">​</a></h3><p>TypeScript 优先的模式验证库，Claude Code 使用 Zod v4 定义工具的输入参数。</p><h2 id="其他" tabindex="-1">其他 <a class="header-anchor" href="#其他" aria-label="Permalink to &quot;其他&quot;">​</a></h2><h3 id="ai-first" tabindex="-1">AI First <a class="header-anchor" href="#ai-first" aria-label="Permalink to &quot;AI First&quot;">​</a></h3><p>以 AI 为核心的设计理念，强调从 AI 的能力和限制出发设计系统。</p><h3 id="dead-code-elimination" tabindex="-1">Dead Code Elimination <a class="header-anchor" href="#dead-code-elimination" aria-label="Permalink to &quot;Dead Code Elimination&quot;">​</a></h3><p>死代码消除，编译时移除不会执行的代码，减小打包体积。</p><h3 id="lazy-loading" tabindex="-1">Lazy Loading <a class="header-anchor" href="#lazy-loading" aria-label="Permalink to &quot;Lazy Loading&quot;">​</a></h3><p>懒加载，延迟加载非必需的资源，提升启动性能。</p><h3 id="parallel-prefetch" tabindex="-1">Parallel Prefetch <a class="header-anchor" href="#parallel-prefetch" aria-label="Permalink to &quot;Parallel Prefetch&quot;">​</a></h3><p>并行预取，同时发起多个数据读取请求，减少总等待时间。</p><h3 id="react-ink" tabindex="-1">React + Ink <a class="header-anchor" href="#react-ink" aria-label="Permalink to &quot;React + Ink&quot;">​</a></h3><p>使用 React 和 Ink 库构建终端用户界面的技术栈。</p><h3 id="streaming-response" tabindex="-1">Streaming Response <a class="header-anchor" href="#streaming-response" aria-label="Permalink to &quot;Streaming Response&quot;">​</a></h3><p>流式响应，API 返回数据的方式，数据逐步到达而非一次性返回全部。</p><hr><h2 id="参考链接" tabindex="-1">参考链接 <a class="header-anchor" href="#参考链接" aria-label="Permalink to &quot;参考链接&quot;">​</a></h2><ul><li><a href="https://docs.anthropic.com" target="_blank" rel="noreferrer">Anthropic API 文档</a></li><li><a href="https://claude.ai/code" target="_blank" rel="noreferrer">Claude Code 官方网站</a></li><li><a href="https://modelcontextprotocol.io" target="_blank" rel="noreferrer">Model Context Protocol</a></li><li><a href="https://vitepress.dev" target="_blank" rel="noreferrer">VitePress 文档</a></li><li><a href="https://zod.dev" target="_blank" rel="noreferrer">Zod 文档</a></li><li><a href="https://bun.sh" target="_blank" rel="noreferrer">Bun 文档</a></li></ul>',128)])])}const m=e(i,[["render",l]]);export{u as __pageData,m as default};
